      d="m5.1 8.716 1.047 5.145a.702.702 0 0 1-1.107-.422l-.814-4.007L.427 7.826A.699.699 0 0 1 .362 6.57l3.603-1.983.38-3.953a.701.701 0 0 1 1.158-.46L8.574 2.85l4.052-.898a.7.7 0 0 1 .786.978l-1.698 3.631-.854-.533 1.388-2.969-3.95.876L5.284 1.31 4.91 5.208 1.388 7.146z"
      fill="#C77D55"
    />
  </svg>
);

export const SparkRun: React.FC<SparkRunProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? SparkRunLight : SparkRunDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
